    const n = prices.length;

    // Calculate the original profit
    let originalProfit = 0;
    for (let i = 0; i < n; i++) {
        originalProfit += strategy[i] * prices[i];
    }
    maxProfit = originalProfit;

    // Try to modify each possible subarray of length k
    for (let i = 0; i <= n - k; i++) {
        // Calculate the profit change if we modify the subarray starting at i
        let profitChange = 0;
        // For the first k/2 elements, change from -1 to 0 (buy to hold)
        for (let j = 0; j < k / 2; j++) {
            profitChange += (0 - strategy[i + j]) * prices[i + j];
        }
        // For the last k/2 elements, change from 1 to 1 (sell remains the same)
        // So no change in profit for these elements
        // But we need to check if the original strategy had 1, and if we change it to 1, no change
        // So no need to do anything for these elements

        // Calculate the new profit after modification
        let newProfit = originalProfit + profitChange;
        if (newProfit > maxProfit) {
            maxProfit = newProfit;
        }
    }

    return maxProfit;
}

